#!/usr/bin/env bash
# doe-cmp.sh — 单元工艺配方开发（DOE 找工艺窗口）— 以刻蚀/沉积/CMP 为代表 SOP walkthrough for 半导体芯片制造工艺.
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="半导体芯片制造工艺"
WORKFLOW="单元工艺配方开发（DOE 找工艺窗口）— 以刻蚀/沉积/CMP 为代表"

usage() {
  cat <<EOF
doe-cmp.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./doe-cmp.sh             # interactive
  ./doe-cmp.sh --dry-run
  ./doe-cmp.sh --json
  ./doe-cmp.sh --explain
  ./doe-cmp.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "单元工艺配方开发（DOE 找工艺窗口）— 以刻蚀/沉积/CMP 为代表" 工作流。

一句话: 从「一个新结构/新材料/新设备没有可用配方」到「锁定一个有足够工艺窗口、可量产、可被 SPC 监控的 recipe」。这是工艺工程师最高频的日常 workflow，刻蚀/沉积/CMP/光刻通用。 (evidence: [T03-S008, T04-S034])

入门 SOP 共 6 步, 失败模式自检 3 项。

相关心智模型:
  • 物理硬约束 ⇄ 良率/成本经济约束（第一性双重张力）: 半导体工艺的每个决策都同时受两类硬约束——物理/化学/材料（量子隧穿、短沟道效应、RC 延迟、热预算、缺陷物理）与良率/成本经济（D0 缺陷密度、每片晶圆成本、wph、折旧）；摩尔定律首先是**经济命
  • 设备/工艺是必要非充分，良率 know-how 才是真壁垒: 能不能做先进制程，从来不是「有没有 EUV/光刻机」单一决定的——设备 + 材料 + 刻蚀/沉积 + 工艺整合 + 良率爬坡**五要素缺一不可**，而良率 ramp 的 know-how 是 silo

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "**定义目标与量测指标**：明确 CD / profile（侧壁角）/ 选择比 selectivity / 去除速率 / 均匀性 / 缺陷 等可量测验收标准，并先建立对应量测方法（CD-SEM/OCD/椭偏）。"
  "**识别关键参数与基线**：列出该工艺的主导参数（刻蚀：气体配比/RF 功率/压力/温度；沉积：前驱体/温度/循环数；CMP：下压力/转速/浆料），从供应商/文献/类似工艺取基线配方。 (evidence: [T03-S008])"
  "**设计 DOE 找工艺窗口**：用筛选 DOE（如两水平正交矩阵）扫主因子，再用响应面 RSM / 中心点定窗口；不要 OFAT（一次一因子）漏掉交互作用。 (evidence: [T04-S034])"
  "**跑实验并量测**：在 split wafer 上跑 DOE 矩阵，量测各 response，建立参数→response 的响应面。"
  "**选工作点并验证窗口宽度**：选位于窗口中心、对参数漂移最不敏感的工作点；工艺窗口宽 = 可制造性好。 (evidence: [T03-S008])"
  "**设 SPC 限并移交**：把工作点参数与量测点写成 SPC 控制图、APC run-to-run 规则，移交量产并持续监控。 (evidence: [T04-S034])"
)
declare -a FAILURE_MODES=(
  "**OFAT 调参漏交互**：只一次调一个参数找到的窗口是假窗口，量产随设备漂移崩 —— 必须用筛选 DOE 至少覆盖主因子的两两交互。"
  "**只在均匀测试片调、不做 loading/edge split**：量产真实图形密度不均，开口大处选择比掉、边缘 CD 漂，良率周期性掉 —— DOE 阶段就加 loading 与 edge split。"
  "**选窗口中心遗漏 = 选了高良率但窄窗口点**：上量产后设备微漂即超规 —— 用 RSM 选对参数漂移最不敏感的工作点。"
)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "doe-cmp-walkthrough"
fi
